import Vue from 'vue'
import Vuex from 'vuex'
import axios from '@/plugins/axios'
Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    login: false,
    loginInfo: null,
    token: null
  },
  getters: {
    // 获取token值
    tokens(state) {
      if (!state.token) {
        state.token = sessionStorage.getItem('token')
      }
      return state.token;
    },
    // 获取loginInfo值
    userMsg(state) {
      if (!state.loginInfo) {
        state.loginInfo = sessionStorage.getItem('logininfo')
      }
      let result =JSON.parse(state.loginInfo)
      // loginInfo的值被转成字符串了，这里需要转为对象
      return result;
    }
  },

  mutations:{
    // 保存token
    saveToken(state, payload) {
      state.token = payload;
      sessionStorage.setItem('token', payload);
    },
    // 保存用户信息
    saveLoginInfo(state, payload) {
      state.loginInfo = payload;
      sessionStorage.setItem('logininfo',JSON.stringify(payload))
    },
      // 退出登录
  loginOut(state){    
    sessionStorage.removeItem("token");
    sessionStorage.removeItem("logininfo");  
    state.token = null;
    state.loginInfo= null;  
  }

  },



  actions: {
    // 获取用户信息
    getLoginInfo(comtext) {
      axios.get('api/user', {
        
      }).then(data => {
        comtext.commit('saveLoginInfo', data.data.data)
      })
    }
  },
  modules: {
  }
})
