import Vue from 'vue'
import VueRouter from 'vue-router'
import Index from '../views/Index'
import store from '../store'

// 解决路由重定向跳转问题
const originalPush = VueRouter.prototype.push;
VueRouter.prototype.push = function push(location, onResolve, onReject) {
if (onResolve || onReject) return originalPush.call(this, location, onResolve, onReject)
return originalPush.call(this, location).catch(err => err);
}
Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Index',
    component: Index
  },
  {
    path:'/category',
    name:"Category",
    component:()=>import('@/views/Category')
  },
  {
    path:'/cart',
    name:"Cart",
    meta:{
    login:true
    },
    component:()=>import('@/views/Cart')
  },
  {
    path:'/my',
    name:"My",
    meta:{
      login:true
      },
    component:()=>import('@/views/My')
  },
  {
    path:'/search',
    name:"Search",
    component:()=>import('@/views/Search')
  },
  {
    path:'/login',
    name:"Login",
    component:()=>import('@/views/Login')
  },

  {
    path:'/more/:li',
    name:"More",
    props:true,
    component:()=>import('@/views/More')
  },
  {
    path:'/productlist/:id',
    props:true,
    name:"ProductList",
    component:()=>import('@/views/ProductList')
  },
  {
    path:'/confirmdetail',
    name:"ConfirmDetail",
    meta:{
      hide:true
      },
    component:()=>import('@/views/ConfirmDetail')
  },
  {
    path:'/transition/:_num',
    props:true,
    name:"Transition",
    meta:{
      hide:true
      },
    component:()=>import('@/views/Transition')
  },
  {
    path:'/prodetail/:_id',
    meta:{
    hide:true
    },
    props:true,
    name:"ProDetail",
    component:()=>import('@/views/ProDetail')
  },
 

  {
    path:'/paysuccess/:num',
    props:true,
    meta:{
    hide:true
    },
    name:"PaySuccess",
    component:()=>import('@/views/PaySuccess')
  },
  {
    path:'/usermodify',
    meta:{
    hide:true
    },
    name:"UserModify",
    component:()=>import('@/views/UserModify')
  },
  {
    path:'/modifycode',
    meta:{
    hide:true
    },
    name:"ModifyCode",
    component:()=>import('@/views/ModifyCode')
  },
  {
    path:'/orderlist',
    meta:{
    hide:true
    },
    name:"OrderList",
    component:()=>import('@/views/OrderList')
  },
]

const router = new VueRouter({
  routes
})
router.beforeEach((to,form,next)=>{
  // 当在购物车及我的页面 + login为false时
  if(to.meta.login ){
    if(!store.getters.tokens||store.getters.tokens == null){
      next("/login");

    }
  }

  next();
})
export default router
